    {
      "action": "read_doc",
      "input": {
        "doc_id": "T-003"
      },
      "step": 1
    },
    {
      "action": "update_ticket",
      "input": {
        "notes": "Tagged as billing (product area) due to duplicate charge inquiry. Set status to needs_review as the explicit next status.",
        "status": "needs_review",
        "ticket_id": "T-003"
      },
      "step": 2
    },
    {
      "action": "send_email",
      "input": {
        "body": "Short summary: Customer reports a duplicate charge. Ticket T-003 has been tagged for billing and set to status needs_review.",
        "subject": "T-003 billing: duplicate charge (status needs_review)",
        "to": "support@example.test"
      },
      "step": 3
    },
    {
      "action": "write_memory",
      "input": {
        "key": "last_processed_ticket",
        "value": "T-003 tagged billing; status set to needs_review; summary emailed to support@example.test."
      },
      "step": 4
    }
  ]
}

